def search_fake_db(product_name: str) -> dict:
    """Search for a product in fake database"""
    product_lower = product_name.lower()
    for key, data in FAKE_PRODUCTS_DB.items():
        if key in product_lower or data["brand"].lower() in product_lower:
            return data
    return None

def add_fake_report(product_name: str, issue: str, location: str = "Pakistan"):
    """Add user report for a fake product"""
    product_lower = product_name.lower()
    for key, data in FAKE_PRODUCTS_DB.items():
        if key in product_lower or data["brand"].lower() in product_lower:
            data["report_count"] += 1
            if issue not in data["fake_indicators"]:
                data["fake_indicators"].append(issue)
            return True
    return False

def get_high_risk_products():
    """Get products with highest fake reports"""
    sorted_products = sorted(FAKE_PRODUCTS_DB.items(), key=lambda x: x[1]["report_count"], reverse=True)
    return sorted_products[:10]

def get_all_categories():
    """Get all product categories"""
    categories = set()
    for data in FAKE_PRODUCTS_DB.values():
        categories.add(data["category"])
    return list(categories)
